    document.body.appendChild(el);
    setTimeout(function() { el.style.opacity = '0'; setTimeout(function() { el.remove(); }, 400); }, 1400);
  }

  function toggleCollapsible() {
    if (_toggling) return;
    _toggling = true;

    var el = document.getElementById('sakuraCollapsible');
    var header = el.querySelector('.sakura-header');

    if (_closeTimer) {
      clearTimeout(_closeTimer);
      _closeTimer = null;
    }

    if (el.classList.contains('expanded')) {
      /* ===== CLOSE SEQUENCE ===== */
      // Step 1: Add closing — stripes transition to left
      el.classList.add('closing');

      // Step 2: After stripes have mostly exited, remove expanded (triggers grid collapse)
      _closeTimer = setTimeout(function() {
        el.classList.remove('expanded');
        header.setAttribute('aria-expanded', 'false');

        // Step 3: After grid finishes collapsing, clean up closing class
        // Reset stripes to right side (ready for next open)
        setTimeout(function() {
          el.classList.remove('closing');
          _toggling = false;
          updateIframeHeight();
        }, 650);

      }, 420);

      setTimeout(updateIframeHeight, 50);

    } else {
      /* ===== OPEN SEQUENCE ===== */
      // Clean any stale closing state
      el.classList.remove('closing');

      // Force stripes to right-side starting position before expanding
      // (They should already be there, but ensure no stale transform)
      var stripes = el.querySelectorAll('.stripe');
      for (var i = 0; i < stripes.length; i++) {
        stripes[i].style.transition = 'none';
        // Read layout to flush the forced style
        void stripes[i].offsetWidth;
        stripes[i].style.transition = '';
      }

      // Now expand — stripes will transition from right to center
      el.classList.add('expanded');
      header.setAttribute('aria-expanded', 'true');
      triggerPetalFall();

      setTimeout(function() { _toggling = false; updateIframeHeight(); }, 700);
      setTimeout(updateIframeHeight, 50);
    }
  }

  function triggerPetalFall() {
    var cw = document.querySelector('.sakura-content-wrapper');
    if (!cw) return;
    var emojis = ['🌸', '💮', '✨'];

    for (var i = 0; i < 8; i++) {
      var p = document.createElement('div');
